#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int n; scanf("%d", &n);
        int val; scanf("%d", &val);
        int mn = val, mx = val;
        for(int i = 1; i < n; ++i){
            scanf("%d", &val);
            if(val < mn) mn = val;
            if(val > mx) mx = val;
        }
        printf("%d %d\n", mn, mx);
    }
    return 0;
}

